interface.definition:
a!localVariables(
  local!eventBookmarks: property(
    #"_a-0000ee50-153e-8000-88de-179188179188_17913"(user: loggedInUser()),
    "data",
    null
  ),
  local!events: #"SYSTEM_SYSRULES_queryRecordType_v2"(
    recordType: #"urn:appian:record-type:v1:fa952da3-a305-45ce-924b-89ca2dab3222",
    pagingInfo: #"SYSTEM_SYSRULES_pagingInfo"(startIndex: 1,batchSize: length(local!eventBookmarks)),
    filters: #"SYSTEM_SYSRULES_queryFilter"(
      field: #"urn:appian:record-field:v1:fa952da3-a305-45ce-924b-89ca2dab3222/8eedcd4f-41f4-4085-889b-efedecf448e2",
      operator: "in",
      value: local!eventBookmarks[#"urn:appian:record-field:v1:50a06c9e-db77-4927-a19e-8aeb88e90db5/c0b749e3-b77a-4cfc-b2ce-7dabb2882dad"],
      applyWhen: a!isNotNullOrEmpty(local!eventBookmarks[#"urn:appian:record-field:v1:50a06c9e-db77-4927-a19e-8aeb88e90db5/c0b749e3-b77a-4cfc-b2ce-7dabb2882dad"])
    )
  ).data,
  local!eventAndBookmarks: #"SYSTEM_SYSRULES_forEach"(
    items: local!eventBookmarks,
    expression: a!map(
      eventBookmark: fv!item,
      event: index(index(local!events,wherecontains(fv!item[#"urn:appian:record-field:v1:50a06c9e-db77-4927-a19e-8aeb88e90db5/c0b749e3-b77a-4cfc-b2ce-7dabb2882dad"],local!events[#"urn:appian:record-field:v1:fa952da3-a305-45ce-924b-89ca2dab3222/8eedcd4f-41f4-4085-889b-efedecf448e2"])),1,null)
    )
  ),
  #"SYSTEM_SYSRULES_sectionLayout_v1"(
    label: #"urn:appian:translation-string:v1:344fc731-49ee-49a0-8be4-8e61ac0e4005",
    labelIcon: "star",
    labelColor: "STANDARD",
    divider: "BELOW",
    showWhen: and(
      ri!showWhen,
      a!isNotNullOrEmpty(local!eventBookmarks)
    ),
    contents: #"SYSTEM_SYSRULES_forEach"(
      items: local!eventAndBookmarks,
      expression: {
        #"SYSTEM_SYSRULES_cardLayout"(
          padding: "EVEN_LESS",
          marginBelow: "NONE",
          marginAbove: "NONE",
          showBorder: false,
          contents: {
            #"SYSTEM_SYSRULES_richTextDisplayField"(
              labelPosition: "COLLAPSED",
              value: {
                #"SYSTEM_SYSRULES_richTextIcon"(
                  icon: "star",
                  caption: #"urn:appian:translation-string:v1:870bd1d5-041b-40b8-a58b-9c8d9b0932b7",
                  linkStyle: "STANDALONE",
                  link: #"SYSTEM_SYSRULES_startProcessLink"(
                    processModel: #"_a-0000ee50-153e-8000-88de-179188179188_17926",
                    processParameters: {
                      eventId:property(fv!item,"eventBookmark",null)[#"urn:appian:record-field:v1:50a06c9e-db77-4927-a19e-8aeb88e90db5/c0b749e3-b77a-4cfc-b2ce-7dabb2882dad"],
                      eventBookmark: property(fv!item,"eventBookmark",null)
                    }
                  )
                ),
                char(160),
                char(160),
                #"SYSTEM_SYSRULES_richTextItem_v1"(
                  color: "STANDARD",
                  link: #"SYSTEM_SYSRULES_recordLink"(
                    recordType: #"urn:appian:record-type:v1:fa952da3-a305-45ce-924b-89ca2dab3222",
                    identifier: property(fv!item,"eventBookmark",null)[#"urn:appian:record-field:v1:50a06c9e-db77-4927-a19e-8aeb88e90db5/c0b749e3-b77a-4cfc-b2ce-7dabb2882dad"]
                  ),
                  text: property(fv!item,"event",null)[#"urn:appian:record-field:v1:fa952da3-a305-45ce-924b-89ca2dab3222/7bd3ce80-0696-4abd-a32c-6f6f775a9f5d"]
                ),
              }
            ),
            #"SYSTEM_SYSRULES_horizontalLine"(
              showWhen: not(fv!isLast),
              marginBelow: "NONE"
            )
          }
        )
      }
    )
  )
)
